Base_基础配置:
!
hostname {{ hostname }}
!
clock timezone BJ 8 0
!
feature lldp
feature lacp
feature interface-vlan
!
username {{ admin_user }} role network-admin password {{ admin_pass }}
username {{ oper_user }} role network-operator password {{ oper_pass }}
username {{ escape_user }} role network-admin password {{ escape_pass }}
!
vlan {{ mgmt_vlan }}
 name MGMT_Management
!
interface Vlan{{ mgmt_vlan }}
 ip address {{ mgmt_ip }} {{ mgmt_mask }}
 no shutdown
!
